#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X1, X2, X3, V1, V2;
        scanf("%d %d %d %d %d", &X1, &X2, &X3, &V1, &V2);
        double timeChef = (double)(X3 - X1) / V1;
        double timeKefa = (double)(X2 - X3) / V2;
        if (timeChef < timeKefa) {
            printf("Chef\n");
        } else if (timeChef > timeKefa) {
            printf("Kefa\n");
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

